{"ideviceId":"20260223071034644C57","textInfoDurationInput":"","textInfoDurationTextInput":"Duration","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Grouping","textTextarea":"<style>

/* ===== BOX ===== */
.exe-kimia-box{
    max-width:900px;
    margin:15px auto;
    padding:28px 28px;
    border-radius:30px;
    border:3px solid #263e8b;
    background:linear-gradient(135deg,#dbe4f2,#c8d3e3);
    box-shadow:0 12px 28px rgba(0,0,0,0.18);
    position:relative;
    overflow:hidden;
}

/* ===== CAPSULE ===== */
.exe-kimia-bar{
    width:92%;
    margin:0 auto 12px auto;
    padding:12px 22px;
    border-radius:999px;
    background:linear-gradient(90deg,#5d73b9,#2441a5);
    color:white;
    font-weight:600;
    text-align:center;
    position:relative;
    overflow:hidden;
}
/* ===== SHIMMER CAPSULE ===== */
.exe-kimia-bar::after{
    content:'';
    position:absolute;
    top:0;
    left:-70%;
    width:45%;
    height:100%;
    background:linear-gradient(
        90deg,
        transparent,
        rgba(255,255,255,0.6),
        transparent
    );
    transform:skewX(-20deg);
    animation:exeShimmer 3s infinite;
}

/* ===== KEYFRAME SHIMMER ===== */
@keyframes exeShimmer{
    0%{left:-70%;}
    100%{left:140%;}
}
/* ===== CONTENT ===== */
.exe-kimia-content{
    min-height:45px;
}

/* ===== ICON KESETIMBANGAN ===== */
.exe-equilibrium{
    position:absolute;
    top:10px;
    right:18px;
    width:75px;
    height:75px;
}

/* animasi cairan */
.exe-liquid{
    animation:liquidWave 3s ease-in-out infinite;
}

/* animasi panah */
.exe-arrow{
    animation:arrowSpin 5s linear infinite;
}

/* animasi bubble */
.exe-bubble{
    animation:bubbleRise 2.5s infinite;
}

/* ===== ANIM ===== */
@keyframes liquidWave{
    0%,100%{transform:translateY(0);}
    50%{transform:translateY(2px);}
}

@keyframes arrowSpin{
    0%{transform:rotate(0deg);}
    100%{transform:rotate(360deg);}
}

@keyframes bubbleRise{
    0%{transform:translateY(6px); opacity:0;}
    50%{opacity:1;}
    100%{transform:translateY(-6px); opacity:0;}
}

</style>
<div class="exe-kimia-box">
