/* ===== BOX ===== */
.exe-nos-box{
    max-width:900px;
    margin:15px auto;
    padding:25px 25px;
    border-radius:28px;
    border:4px solid #2f7d32;
    background:#dff3e3;
    box-shadow:0 10px 24px rgba(0,0,0,0.15);
    position:relative;
}

/* ===== CONTENT ===== */
