    min-height:50px; /* supaya editable */
}

/* ===== NOS ICON ===== */
.exe-nos-icon{
    position:absolute;
    top:14px;
    right:16px;
    width:65px;
    height:65px;
    opacity:.28;
}

/* orbit anim */
.exe-nos-icon .orbit{
    transform-origin:center;
    animation:nosOrbit 8s linear infinite;
}

/* leaf anim */
.exe-nos-icon .leaf{
    animation:nosLeaf 3s ease-in-out infinite;
}

/* ===== ANIM ===== */
@keyframes nosOrbit{
    from{transform:rotate(0);}
    to{transform:rotate(360deg);}
}

@keyframes nosLeaf{
    0%,100%{transform:translateY(0);}
    50%{transform:translateY(-3px);}
}

